        TO_ENSURE_PROMPT_TRANSPORTATION_TO_THE_FRONTLINES_I                   = 7177,  -- To ensure prompt transportation to the frontlines, I have been given clearance to teleport troops to locations on the Quon and Mindartia theaters.
        PLEASE_SELECT_A_DESTINATION_I_DO_NOT_REQUIRE                          = 7178,  -- Please select a destination: I do not require your services. Xarcabard [y|z/ySanz/yBasz/yWinz/yBstz] Beaucedine Glacier[y|z/ySanz/yBasz/yWinz/yBstz] Batallia Downs [y|z/ySanz/yBasz/yWinz/yBstz] Rolanberry Fields [y|z/ySanz/yBasz/yWinz/yBstz] Sauromugue Champaign [y|z/ySanz/yBasz/yWinz/yBstz] Jugner Forest [y|z/ySanz/yBasz/yWinz/yBstz] Pashhow Marshlands [y|z/ySanz/yBasz/yWinz/yBstz] Meriphataud Mountains [y|z/ySanz/yBasz/yWinz/yBstz] Vunkerl Inlet [y|z/ySanz/yBasz/yWinz/yBstz] Grauberg [y|z/ySanz/yBasz/yWinz/yBstz] Fort Karugo-Narugo [y|z/ySanz/yBasz/yWinz/yBstz] East Ronfaure [y|z/ySanz/yBasz/yWinz/yBstz] North Gustaberg [y|z/ySanz/yBasz/yWinz/yBstz] West Sarutabaruta [y|z/ySanz/yBasz/yWinz/yBstz] Southern San d'Oria [y|z/ySanz/yBasz/yWinz/yBstz] Bastok Markets [y|z/ySanz/yBasz/yWinz/yBstz] Windurst Waters [y|z/ySanz/yBasz/yWinz/yBstz] Garlaige Citadel [y|z/ySanz/yBasz/yWinz/yBstz] Crawlers' Nest [y|z/ySanz/yBasz/yWinz/yBstz] Eldieme Necropolis [y|z/ySanz/yBasz/yWinz/yBstz]
