        GREETINGS_I_AM_CAMPAIGN_ARBITER_FOR_THE_ALLIED_2                      = 7191,  -- Greetings. I am , Campaign Arbiter for the Allied Forces.
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_PERFORMANCE                          = 7192,  -- What can I help you with? Nothing. Performance assessment. New Allied Tags. Temporary items. Union registration. Teleportation. Information on the Allied Campaign.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_NOTHING_I                                 = 7193,  -- What would you like to know? Nothing. I'm sorry. About performance assessment. About Allied Tags. About temporary items. About Unions.
        I_AM_SORRY_BUT_AT_THIS_TIME_I                                         = 7194,  -- I am sorry, but at this time, I cannot be of any assistance in that area.
        UNDERSTOOD_I_SHALL_NOW_JUDGE_YOUR_PERFORMANCE_AND                     = 7195,  -- Understood. I shall now judge your performance and award the proper remuneration.
        AH_I_M_SORRY_TO_INFORM_YOU_THAT                                       = 7196,  -- Ah, I'm sorry to inform you that your performance has not earned you any compensation.
        UNDERSTOOD_I_SHALL_PREPARE_A_NEW_SET_OF                               = 7197,  -- Understood. I shall prepare a new set of tags for you now.
        YOU_VE_ALREADY_UNDERGONE_AN_EVALUATION_FOR_THIS                       = 7198,  -- You've already undergone an evaluation for this battle, or had you forgotten? As much as I'd like to, I'm forbidden from providing you with a new set of Allied Taegs until the next battle begins.
        ANYONE_WEARING_ALLIED_TAGS_WHILE_PARTICIPATING_IN_A                   = 7199,  -- Anyone wearing Allied Tags while participating in a campaign battle will be judged on their overall performance.
        SOLDIERS_WILL_BE_EVALUATED_NOT_ONLY_ON_THEIR                          = 7200,  -- Soldiers will be evaluated not only on their fighting skills, but also on how much they contribute to the efforts of their allies through means such as healing and enhancing.
        HOWEVER_BEWARE_THAT_IF_YOU_LEAVE_THE_AREA                             = 7201,  -- However, beware that if you leave the area before being assessed, you will be deemed a deserter and will forfeit all rewards earned that day.
        ALSO_WHILE_THERE_ARE_NO_IMMEDIATE_PENALTIES_FOR                       = 7202,  -- Also, while there are no immediate penalties for being knocked out, falling in battle will significantly lower the score given to you.
        WHEN_YOU_ARE_READY_TO_RECEIVE_COMPENSATION_FOR                        = 7203,  -- When you are ready to receive compensation for your work on the field, return to me and I shall assess your performance and provide you with your payment.
        ALLIED_TAGS_ARE_A_SPECIAL_TYPE_OF_IDENTIFICATION                      = 7204,  -- Allied Tags are a special type of identification given to all participants of Allied Campaign battles.
        THERE_ARE_BENEFITS_AS_WELL_AS_DRAWBACKS_TO                            = 7205,  -- There are benefits, as well as drawbacks, to wearing the tags. One of the benefits is that in the case you are knocked out on the battlefield, you will not lose any experience points.
        HOWEVER_SOME_OF_THE_DRAWBACKS_INCLUDE_THE_INABILITY                   = 7206,  -- However, some of the drawbacks include the inability to improve skills and earn experience points for individual kills, as well as the right to loot fallen enemies.
        TEMPORARY_ITEMS_CAN_BE_PURCHASED_IN_EXCHANGE_FOR                      = 7207,  -- Temporary items can be purchased in exchange for Allied Notes.
        THERE_ARE_SEVERAL_DIFFERENT_VARIETIES_OF_ITEMS_BUT                    = 7208,  -- There are several different varieties of items, but they all have one thing in common--they can only be used on the battlefield they were issued.
        IT_IS_HIGHLY_RECOMMENDED_THAT_YOU_FIRST_SURVEY                        = 7209,  -- It is highly recommended that you first survey a battle's conditions and then select the supplies that you believe will benefit you most.
        PLEASE_REMEMBER_THAT_ALL_TEMPORARY_ITEMS_YOU_CARRY                    = 7210,  -- Please remember that all temporary items you carry on your person will be confiscated in the event that you leave the area.
        YOU_CAN_ONLY_PURCHASE_TEMPORARY_ITEMS_IF_YOUR                         = 7211,  -- You can only purchase temporary items if your nation of allegiance is commanding the campaign.
