        TELEPORT_CURRENT_GIL_YES_PLEASE_NO_THANK_YOU                          = 10897,  -- Teleport? (Current gil: #) [Add to favorites/Remove from favorites]. Yes, please. No, thank you.
        TELEPORT_TO_WHICH_REGION_ON_SECOND_THOUGHT_NONE                       = 10898,  -- Teleport to which region? On second thought, none. Select from favorites. Current region. [San d'Oria/Movalpolos]. [Bastok/Tavnazian Arch]. [Windurst/Lumoria]. [Jeuno/Mamool Ja Savage]. [Tavnazia/Halvung]. [West. Aht Urhgan/Arrapago Is]. [Adoulin Isles/Ruins of Alzadaal]. [Ronfaure/Ronfaure Front]. [Zulkheim/Norvallen Front]. [Norvallen/Gustaberg Front]. [Gustaberg/Derfland Front]. [Derfland/Sarutabaruta Front]. [Sarutabaruta/Aragoneu Front]. [Kolshushu/Fauregandi Front]. [Aragoneu/Valdeaunia Front]. [Fauregandi/East. Ulbuka]. [Valdeaunia/Ra'Kaznar]. [Qufim/]. [Li'Telor/]. [Kuzotz/]. [Vollbow/]. [Elshimo Low/]. [Elshimo Up/]. [Tu'Lia/]. Previous page. Next page.
        TELEPORT_WHERE_NONE_OF_THESE_A_FAVORITED_LOCATION                     = 10899,  -- Teleport where? None of these. A favorited location. An original area. A Rise of the Zilart area. A Chains of Promathia area. A Treasures of Aht Urhgan area. A Wings of the Goddess area. A Seekers of Adoulin area.
        YOU_MAY_CHANGE_THE_METHOD_OF_SELECTING_THE                            = 10900,  -- You may change the method of selecting the area of your desired home point to teleport to.
