        AH_NEVER_MIND_FORGET_YOU_HEARD_ANYTHING_FROM                          = 11775,  -- Ah, never mind. Forget you heard anything from me.
        WHAT_THE_HELL_IS_THIS_DO_I_LOOK                                       = 11776,  -- What the hell is this? Do I look like a goldsmith? Get that thing out of my face!
