        SELECT_CAMPAIGN_OPS_WITHIN_THE_MISSIONS_MENU_TO                       = 12295,  -- Select Campaign Ops within the Missions menu to view operation orders.
        OUCH_I_M_SORRY_ALL_POSITIONS_FOR_THAT                                 = 12296,  -- Ouch... I'm sorry, %. All positions for that operation have been filled. You'll have to trrry another one.
        HOLD_UP_YOU_DON_T_HAVE_ENOUGH_OP                                      = 12297,  -- Hold up... You don't have enough Op Credits to join any operations. Back to the barracks, buddy! I'll see you tomorrow!
        WHOA_I_DIDN_T_EXPECT_TO_SEE_YOU                                       = 12298,  -- Whoa... I didn't expect to see you back so soon.
        IS_THERE_SOMETHING_WRONG_I_M_ABORTING_THE                             = 12299,  -- Is there something wrong? I'm aborting the operation. I just came to see you/I just came to say hello].
        WELL_I_M_FLATTERRRED_BUT_THIS_AIN_T                                   = 12300,  -- Well, I'm flatterrred, but this ain't going to earn you any points with the major. You'd better get back out therrre if you value your hide.
        WHAT_I_WASN_T_LISTENING_COULD_YOU_RRREPEAT                            = 12301,  -- ...What? I wasn't listening. Could you rrrepeat that?
        HUH_AND_I_HAD_YOU_PEGGED_FOR_A                                        = 12302,  -- Huh... And I had you pegged for a harrrd worker... I guess it goes to show you can't judge a book by its cover. Maybe you should considerrr a different line of work.
        AH_BACK_AT_LAST_LET_S_HEARRR_ALL                                      = 12303,  -- Ah, %. Back at last. Let's hearrr all about your latest escapades...
        ID_12304                                                              = 12304,  -- [......<Sigh>....../......Hmmm....../......I see...!]
        I_KNEW_FROM_THE_MOMENT_YOU_WALKED_UP                                  = 12305,  -- I knew from the moment you walked up here you'd come thrrrough, %. The boss...I mean, Major Mihgo will be pleased.
