        CURRENT_NATION_STATUS_FUNDS_UNKNOWN_SUPPLIES_UNKNOWN_TACTICS          = 12344,  -- Current nation status: Funds: [UNKNOWN/ Supplies: [UNKNOWN/ Tactics: [UNKNOWN/
        SKILL_UNKNOWN_PRODUCTION_UNKNOWN                                      = 12345,  -- Skill: [UNKNOWN/ Production: [UNKNOWN/
        HO_HO_HO_KOLIN_OLIN_KNOWS_A_COBRA                                     = 12346,  -- Ho ho ho! Kolin-Olin knows a Cobra when he sees a Cobra, yes he does!
        YOU_VE_COME_TO_LEARN_ALL_ABOUT_THE                                    = 12347,  -- You've come to learn all about the Allied Campaign, have you not? I know you ha`ve!
        WHAT_WOULD_YOU_LIKE_TO_KNOW_WHAT_IS                                   = 12348,  -- What would you like to know? What is the Allied Campaign? What are campaign operations? What are freelances? Nothing.
        THE_ALLIED_CAMPAIGN_IS_THE_COMPREHENSIVE_NAME_GIVEN                   = 12349,  -- The Allied Campaign is the comprehensive name given to the various operations carried out by the Forces of Altana against the Beastman Confederate.
        ARTICLE_1_DOMINION_IS_GRANTED_THE_NATION_THAT                         = 12350,  -- Article 1: Dominion is granted the nation that provides the largest contribution in regaining control of an area occupied by the beastmen.
        ARTICLE_2_IN_EXCHANGE_FOR_THE_RENOUNCING_OF                           = 12351,  -- Article 2: In exchange for the renouncing of all claims to lands seized by their army, campaign arbitration has been bestowed upon the Grand Duchy of Jeuno.
        PHEW_DID_YOU_KNOW_IT_TOOK_ME_TWO                                      = 12352,  -- Phew... Did you know it took me two weeks to memorize the charter? Two weeks! Two...weeks!
        ANYWAY_TO_PUT_IT_SIMPLY_THE_LEADERS_OF                                = 12353,  -- Anyway, to put it simply, the leaders of Jeuno were first to recognize that it would be difficult for Bastok, Windurst, and San d'Oria to cast aside all past differences and join hands on the battlefield. And that's why the Duchy felt it necessary to motivate the armies by offering rewards for their performance.
        IT_S_HOW_THE_NATIONS_HAVE_BEEN_DEALING                                = 12354,  -- It's how the nations have been dealing with each other for the past few centuries, so why try to change things, right? Right? Windurst can keep on doing what it does best, and gain territory, resources, and labor in the process.
        AS_A_MEMBER_OF_THE_DIGNIFIED_COBRA_UNIT                               = 12355,  -- As a member of the dignified Cobra Unit, you'll be required to participate in various sorts of campaign operations to make sure the star of the Federation shines brightaru!
        CAMPAIGN_OPERATIONS_ALSO_KNOWN_AS_CAMPAIGN_OPS_IS                     = 12356,  -- Campaign operations, also known as Campaign Ops, is the term used for the long list of small-scale missions authorized by the Allied War Council in Jeuno. Ever heard of the Allied War Council? Yeah? No?
        ANYWAY_IT_DOESN_T_MATTER_WHEN_AN_OPERATION                            = 12357,  -- Anyway, it doesn't matter. When an operation is successfully completed, the nation is rewarded with extra battle funding, paid for by the Repositorium--an international bank founded by the four nations of Mindartia and Quon, and located in Jeuno.
        TO_PUT_IT_IN_LAY_TERMS_YOU_RE                                         = 12358,  -- To put it in lay terms, you're our proverbial cash cow, %! Have you ever seen a cow?
        OH_BUT_DON_T_START_MAKING_PLANS_TO                                    = 12359,  -- Oh, but don't start making plans to buy that summer home in Bibiki just yet. You see, none of those funds go directly to individual mercenaries. You get paid with Allied Notes, which you can use to purchase supplies and equipment...or equipment and supplies, whichever you wish.
        ALSO_THE_MORE_OPERATIONS_YOU_ACCOMPLISH_THE_MORE                      = 12360,  -- Also, the more operations you accomplish, the more operations will become available to you. It's like a never-ending roller coaster...of operations!
        NOW_UNLESS_YOU_HAVE_ANY_MORE_QUESTIONS_TALK                           = 12361,  -- Now, unless you have any more questions, talk with Emhi Tchaoryo here and she'll help you sign up!
        READY_TO_HIT_THE_BATTLEFIELD_SO_SOON_FEISTY                           = 12362,  -- Ready to hit the battlefield so soon? Feisty, aren't we! Uh... Feisty, aren't you! Well, before you go, let me explain a little about the Allied Campaign map.
        TO_VIEW_THE_CAMPAIGN_MAP_FIRST_SELECT_REGION                          = 12363,  -- To view the campaign map, first select Region Info, and then Campaign.
        THE_SWORD_INDICATES_AREAS_WHERE_BATTLES_ARE_CURRENTLY                 = 12364,  -- The sword indicates areas where battles are currently being waged.
        IF_YOU_ARE_NOT_SIGNED_UP_FOR_ANY                                      = 12365,  -- If you are not signed up for any operations, then hurry to the frontlines and join your fellow legionnaires.
        THE_HEROISM_GAUGE_INDICATES_LOCATIONS_WHERE_THE_BATTLES               = 12366,  -- The heroism gauge indicates locations where the battles have become quite heated. Who knows what may occur in an area with a full gauge?
        THAT_S_IT_NOW_GET_OUT_THERE_AND                                       = 12367,  -- That's it! Now get out there and start shredding those beastmen to dust! Shred to dust...? Whatever, you know what to do!
        FREELANCES_ARE_WHAT_WE_CALL_ROGUE_MERCENARIES_WHO                     = 12368,  -- Freelances are what we call rogue mercenaries who have not pledged allegiance to any nation.
        THESE_GROUPS_DO_NOT_FALL_UNDER_CONTROL_OF                             = 12369,  -- These groups do not fall under control of the Allied Forces; they play by their own rules, not our rules, which wouldn't be their rules. Heroes for hire, you could say...or not.
        BUT_MOST_OF_THEM_ARE_QUITE_TALENTED_ON                                = 12370,  -- But most of them are quite talented on the battlefield. If there were only a way to convince them to fight for the Federation...
        HEY_I_JUST_HAD_AN_IDEA_WHY_DON                                        = 12371,  -- Hey! I just had an idea! Why don't you ask them to join us! Who could turn down a face like that? We're counting on you, %...or at least your face!
        HOLD_ON_YOU_RE_NOT_ONE_OF_OUR                                         = 12372,  -- Hold on, you're not one of our mercenaries, are you? If you're thinking about signing up, go talk to Captain Miah Riyuh. She'll help you out.
        HOLD_ON_YOU_RE_NOT_ONE_OF_OUR_2                                       = 12373,  -- Hold on, you're not one of our mercenaries, are you? If you're thinking about leaving that nation you work for now and signing up with us, go talk to Mhoti Pyiahrs. She'll help you out.
        HEY_YOU_RE_IN_THE_WAY_WE_FORTIFYIN                                    = 12374,  -- Hey, you're in the way. We fortifyin' this here wall to withstand the beastmen's siege turrets. So how's about just gettin' outta here before you get hurt.
        UNLESS_YOU_RE_WILLIN_TO_WIPE_THAT_HELPLESS                            = 12375,  -- Unless you're willin' to wipe that helpless look off your face and lend us a hand. That'd be a different story.
        ASSIST_WITH_THE_FORTIFICATIONS_SHOW_THEM_HOW_IT                       = 12376,  -- Assist with the fortifications? Show them how it's done! Refuse to help. Ask for an explanation.
        ALRIGHT_THAT_S_THE_SPIRIT_LET_S_GET                                   = 12377,  -- Alright! That's the spirit! Let's get a move on, then.
        HMPH_I_FIGURED_AS_MUCH_BY_LOOKIN_AT                                   = 12378,  -- Hmph, I figured as much by lookin' at you. Beat it, then. This is no place for tourists.
        LIKE_I_SAID_IN_PREPARATION_FOR_AN_ENEMY                               = 12379,  -- Like I said, in preparation for an enemy assault, we're workin' to fortify these defensive barriers. If you're willin', I'd like to place you in charge of managin' these here craftsmen as they go about it.
        TO_BE_MORE_PRECISE_ONCE_YOU_GET_TO                                    = 12380,  -- To be more precise, once you get to each craftsman's position, you have to tell 'em exactly what I'm about to tell you. Namely, what type of crystal they need to be usin'. That's all there is to it.
        THE_YOUNG_ELVAAN_WEARIN_THE_RED_HAT_IS                                = 12381,  -- The young Elvaan wearin' the red hat is a blacksmith. Make sure he's using fire crystals.
        THE_ADORABLE_LITTLE_TARUTARU_WITH_THE_BLONDE_BRAIDS                   = 12382,  -- The adorable little Tarutaru with the blonde braids is laying plaster. Gonna have to get her on some ice crystals.
        THE_HUME_LADY_IS_A_STONEMASON_AND_A                                   = 12383,  -- The Hume lady is a stonemason, and a darn good one. She's gonna be needin' wind crystals.
        THAT_OLD_COOT_OF_AN_ELVAAN_WITH_THE                                   = 12384,  -- That old coot of an Elvaan with the huge axe strapped across his back is a carpenter. Famous 'round these parts. Make sure you get him workin' with earth crystals.
        MAY_NOT_LOOK_IT_BUT_THE_MITHRA_WITH                                   = 12385,  -- May not look it, but the Mithra with the black kerchief wrapped 'round her noggin is an architect. She's gonna need her lightning crystals.
        THAT_SPRAT_OF_A_TARUTARU_WEARIN_THE_BLUE                              = 12386,  -- That sprat of a Tarutaru wearin' the blue getup's a handy lil' plumber. Surin' he'll be wantin' his water crystals, no doubt.
        THE_GOOD_LOOKING_FELLA_IN_ALL_WHITE_DOES                              = 12387,  -- The good-looking fella in all white does scaffoldin'. Young Hume lad. See to it he's usin' light crystals.
        THE_LADY_ELVAAN_S_A_PAINTER_HANDLES_A                                 = 12388,  -- The lady Elvaan's a painter. Handles a brush like nobody I never seen. Need dark crystals in that line of work. And that's it.
        AHHH_ONE_MORE_THING_IF_YOU_RE_TOO                                     = 12389,  -- Ahhh, one more thing. If you're too late issuin' your orders, they're liable to up and leave their posts. So be right, and be quick.
        CHOOSE_A_CRYSTAL_FIRE_CRYSTAL_ICE_CRYSTAL_WIND                        = 12390,  -- Choose a crystal! Fire crystal. Ice crystal. Wind crystal. Earth crystal. Lightning crystal. Water crystal. Light crystal. Dark crystal. Plumb give up.
        HEY_NOW_YOU_RE_RUNNIN_THIS_HERE_OPERATION                             = 12391,  -- Hey now, you're runnin' this here operation! You can't just quit! There's no quitting in war!
        WOW_YOU_SURE_BOTCHED_THAT_JOB_ALL_THEM                                = 12392,  -- Wow... You sure botched that job. All them wrong orders threw the craftsmen off kilter. They're demandin' a new foreman.
        WELL_THE_GOOD_NEWS_IS_YOU_RE_GETTIN                                   = 12393,  -- Well, the good news is you're gettin' your orders right. The bad news is that you're takin' your sweet time doing it. We'll never be ready for the Beastmen at this rate.
        COME_ON_NOW_YOU_EVEN_WANT_TO_WIN                                      = 12394,  -- Come on, now! You even want to win this war!? The craftsmen are startin' to strike thanks to your incompetence!
        CX_VF                                                                 = 12395,  -- ^CX^vF#
        G_CF_B                                                                = 12396,  -- g[^^CF#b
        REAA_NPCL                                                             = 12397,  -- rEAA=NPCL%
        LXZF                                                                  = 12398,  -- ]LxzF[bl?/$%/$a%/AM]
        AH_YOU_MUST_BE_WE_VE_BEEN_EXPECTING                                   = 12399,  -- Ah, you must be %. We've been expecting you.
        THE_DELIVERY_TOOK_YOU_AND_EARTH_TIME                                  = 12400,  -- The delivery took you # [hour/hours] (# [minute/minutes] and # [second/seconds] Earth time).
        THE_DELIVERY_TOOK_YOU_AND_EARTH_TIME_2                                = 12401,  -- The delivery took you # [minute/minutes] (# [minute/minutes] and # [second/seconds] Earth time).
        WHILE_YOU_WERE_DAWDLING_YOUR_WAY_HERE_A                               = 12402,  -- While you were dawdling your way here, a separate shipment of construction materials was delivered to us. We shan't be requiring anymore.
        I_COMMEND_YOU_ON_YOUR_EXPEDITIOUSNESS_THANKS_TO                       = 12403,  -- I commend you on your expeditiousness. Thanks to you, the construction work on our provision storehouse here can proceed as planned.
        SO_YOU_HAVE_SOMETHING_TO_ASPIRE_TO_THE                                = 12404,  -- So you have something to aspire to, the quickest delivery thus far was made by %. That indefatigable soldier traversed the same course as you in just # [hour/hours] (# [minute/minutes] and # [second/seconds] Earth time).
        YOU_RE_THE_CURRENT_QUICKEST_DELIVERY_RECORD_HOLDER                    = 12405,  -- You're the current quickest delivery record holder, with a lightning-fast time of # [hour/hours] (# [minute/minutes] and # [second/seconds] Earth time). But that's no excuse to slack off, you hear?
        TIME_ELAPSED_VANA_DIEL_TIME_AND_EARTH_TIME                            = 12406,  -- Time elapsed: # [hour/hours] (Vana'diel time) # [minute/minutes] and # [second/seconds] (Earth time)
        YOU_FIND_NOTHING_OUT_OF_THE_ORDINARY                                  = 12407,  -- You find nothing out of the ordinary.
        A_SHIVER_RUNS_DOWN_YOUR_SPINE                                         = 12408,  -- A shiver runs down your spine...
        PERHAPS_YOU_SHOULD_FIRST_ATTEND_TO_MORE_PRESSING                      = 12409,  -- Perhaps you should first attend to more pressing matters...
        SOMETHING_TELLS_YOU_THAT_YOU_SHOULD_WAIT_A                            = 12410,  -- Something tells you that you should wait a moment and try again.
        I_AM_FAR_TOO_BUSY_TO_SPEAK_WITH                                       = 12411,  -- I am far too busy to speak with you now. Perhaps I'll have a little time later.
        GOOD_SHOW_ON_YOUR_LAST_OPERATION_NOW_GO                               = 12412,  -- Good show on your last operation. Now go make an official report to Sir Rasdinice.
        GOOD_WORK_ON_THAT_LAST_OPERATION_NOW_REPORT                           = 12413,  -- Good work on that last operation. Now report back to First Centurion Hieronymus before he has your hide!
        NICE_JOB_ON_YOUR_LAST_OPERATION_NOW_DON                               = 12414,  -- Nice job on your last operation. Now don't forget to report back to Emhi Tchaoryo!
        IT_SEEMS_THAT_YOU_WERE_NOT_SUCCESSFUL_IN                              = 12415,  -- It seems that you were not successful in your last operation. But do not let one small failure hang heavy on your soul. Report to Sir Rasdinice and put this all behind you.
        WEREN_T_SO_LUCKY_DURING_THAT_LAST_OPERATION                           = 12416,  -- Weren't so lucky during that last operation, were you? Well, don't worry about it too much. Report to First Centurion Hieronymus and get some rest, soldier.
        HMMM_DIDN_T_DO_SO_WELL_ON_THAT                                        = 12417,  -- Hmmm... Didn't do so well on that last operation, did you? I know it's hard, but it's better if you're up-front about these things. If you know what's good for you, you'll hurry down and report to Emhi Tchaoryo before the major finds out first.
        MAKE_HASTE_SIR_RASDINICE_AWAITS_YOUR_REPORT                           = 12418,  -- Make haste, %. Sir Rasdinice awaits your report!
        WHAT_ARE_YOU_WAITING_FOR_REPORT_TO_FIRST                              = 12419,  -- What are you waiting for, %? Report to First Centurion Hieronymus on the double!
        WHY_ARE_YOU_WASTING_YOUR_TIME_CHATTING_WITH                           = 12420,  -- Why are you wasting your time chatting with me? Shouldn't you be reporting to Emhi Tchaoryo?
        GOOD_WORK_SOLDIER_THANKS_YOU_FOR_YOUR_COOPERATION                     = 12421,  -- Good work, soldier. [The Kingdom/The Republic/The Federation] thanks you for your cooperation.
        I_AM_CHARGED_WITH_THE_PROVISIONING_OF_SUPPLIES                        = 12422,  -- I am charged with the provisioning of supplies for our troops out on the battlefield. I can issue you temporary items in exchange for Allied Notes.
        SELECT_A_TEMPORARY_ITEM_PRICE_NOTHING_AT_THIS                         = 12423,  -- Select a temporary item. (Price) Nothing at this time. Browse another page. %...(#) %...(#) %...(#) %...(#) %...(#) %...(#) %...(#) %...(#) Next page. Previous page.
        SELECT_A_TEMPORARY_ITEM_PRICE_STOCK_NOTHING_AT                        = 12424,  -- Select a temporary item. (Price/Stock) Nothing at this time. Browse another page. %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) Next page. Previous page.
        BROWSE_WHICH_PAGE_NEVER_MIND_PAGE_1_PAGE                              = 12425,  -- Browse which page? Never mind. Page 1. Page 2. Page 3. Page 4.
        IT_APPEARS_YOU_RE_ALREADY_IN_POSSESSION_OF                            = 12426,  -- It appears you're already in possession of one. I'm sorry, but we can only afford to issue supplies to those who are most in need.
        I_M_SORRY_BUT_WE_RE_FRESH_OUT                                         = 12427,  -- I'm sorry, but we're fresh out of stock for that item.
        YOU_MUST_ATTAIN_A_HIGHER_RANK_IF_YOU                                  = 12428,  -- You must attain a higher rank if you wish to be issued %.
        IS_THERE_ANYTHING_ELSE_YOU_REQUIRE                                    = 12429,  -- Is there anything else you require?
        LET_THE_BLADE_OF_THE_CONQUEROR_ONCE_AGAIN                             = 12430,  -- Let the Blade of the Conqueror once again bring glory to the Kingdom!
        GWAHAHAHA_LET_ME_COOL_YOU_OFF_A_LITTLE                                = 12431,  -- Gwahahaha! Let me cool you off a little before I send you to hell!
        FATHER_LEND_ME_YOUR_STRENGTH                                          = 12432,  -- Father! Lend me your strength!
        FOR_THE_KING                                                          = 12433,  -- For the king!
        MY_SPEAR_IS_LIGHTNING_AND_YOUR_SCREAM_SHALL                           = 12434,  -- My spear is lightning...and your scream shall be the thunder which follows my mighty strike!
        HA_HAH_YOUR_ARROWS_CANNOT_PIERCE_THE_IRON                             = 12435,  -- Ha hah! Your arrows cannot pierce the iron will of a true knight!
        THIS_ARROW_TO_YOUR_HEART_SHALL_BE_ALTANA                              = 12436,  -- This arrow to your heart shall be Altana's final judgment.
        SHOGYO_MUJO_ZESHO_MEPPO_SHOMETSU_METSUI_JAKUMETSU_IRAKU               = 12437,  -- Shogyo Mujo! Zesho Meppo! Shometsu Metsui! Jakumetsu Iraku!
        THERE_IS_NO_ESCAPE_SAVE_DEATH                                         = 12438,  -- There is no escape...save death!
        ALTANA_LET_YOUR_DIVINE_LIGHT_GUIDE_US_TO                              = 12439,  -- Altana! Let your divine light guide us to victory!
        YOU_BARBARIANS_WILL_REGRET_THE_DAY_YOU_SET                            = 12440,  -- You barbarians will regret the day you set foot on Bastokan soil!
        RYAAAAAAAAAH                                                          = 12441,  -- Ryaaaaaaaaah!
        MEN_DO_NOT_FEAR_THE_ENEMY_IT_IS                                       = 12442,  -- Men! Do not fear the enemy! It is our blades they shall fear!
        A_SWIFT_END_IS_THE_ONLY_MERCY_YOU                                     = 12443,  -- A swift end is the only mercy you will receive from me, fiends!
        WATCH_CAREFULLY_BECAUSE_THIS_IS_THE_LAST_THING                        = 12444,  -- Watch carefully, because this is the last thing you'll ever see in this life!
        I_NEVER_LIKED_FIGHTING_ON_LAND_NOW_GIVE                               = 12445,  -- I never liked fighting on land... Now, give me a well armed battleship on the open sea, and I'll have those turtlebacks running for their lives!
        A_SOLDIER_ALWAYS_COMES_PREPARED_HEHEHEHE                              = 12446,  -- A soldier always comes prepared! Hehehehe!
        TO_YOUR_SEATS_BOYS_THE_SHOW_IS_ABOUT                                  = 12447,  -- To your seats, boys! The show is about to begin!
        AHAHAHAHA_MY_HAND_SLIPPED                                             = 12448,  -- Ahahahaha! My hand slipped!
        THIS_IS_YOUR_LAST_CHANCE_THROW_DOWN_YOUR                              = 12449,  -- This is your last chance. Throw down your weapons and your life will be spared. If you refuse...
        THE_GATES_TO_THE_UNDERWORLD_HAVE_OPENED_I                             = 12450,  -- The gates to the underworld have opened! I'll see you on the other side...or not! Wahahahahah!
        THERE_IS_NOTHING_MORE_MAGNIFICENT_THAN_THE_DANCE                      = 12451,  -- There is nothing more magnificent than the dance of flames on the battlefield!
        PHEW_I_THINK_I_VE_HAD_ENOUGH_OF                                       = 12452,  -- <Phew!> I think I've had enough of this volume!
        GUTTLER_GUTTLER_THIRSTY_GUTTLER_WANT_BLOOD_MORE_BLOOD                 = 12453,  -- Guttler: Guttler thirsty! Guttler want blood! More blood!
        TIME_TO_GO_TO_WORK                                                    = 12454,  -- Time to go to work!
        INVINCIBLE_INDESTRUCTIBLE_INDUBITABLE_THE_AGE_OF_THE_CARDIANS         = 12455,  -- Invincible! Indestructible! Indubitable! The age of the Cardians is upon us!
        YOU_OVER_THERE_NO_WAIT_YOU_RE_SUPPOSED                                = 12456,  -- You, over there. No, wait! You're supposed to be on that side! Hold on, which one were you again? Arrrghhh!
        SNORRRE_IS_THAT_THE_BEST_YOU_CAN_DO                                   = 12457,  -- <Snorrre>... Is that the best you can do?
        PETTY_BEASTMAN_HORDES_ARE_NOTHING_COMPARED_TO_GIANT                   = 12458,  -- Petty beastman hordes are nothing compared to giant wildebeests of homeland! I swat you all down like fruit flies!
        YAWN_UM_HOLY_LIGHT_SHOW_THE_WAY                                       = 12459,  -- <Yawn>... Um... Holy light...show the way...?
        THE_PROTECTION_OF_THE_THRONE_COMES_BEFORE_ALL                         = 12460,  -- The protection of the throne comes before all else. Only by direct order of the royaulais will I wield my blade on the battlefield. Such is the duty of the Royal Guards.
        HAH_HAH_HAH_THE_RINGING_OF_STEEL_UPON                                 = 12461,  -- Hah hah hah! The ringing of steel upon steel! The dripping stench of the battlefield! What could be better than war? The nobles can have their balls, I'll do my dance on the front lines!
        HOW_DARE_A_BASEBORN_PEASANT_RAISE_HIS_HER                             = 12462,  -- How dare a baseborn peasant raise his/her] voice to a noble knight!? Begone, before I strike you down myself!
        THE_KINGDOM_S_DEFEAT_AT_JUGNER_STILL_STINGS                           = 12463,  -- The Kingdom's defeat at Jugner still stings. To avenge the souls of those lost on that fateful day, we must join hands and take up arms as one.
        NOT_ONCE_IN_THE_FOUR_HUNDRED_YEARS_SINCE                              = 12464,  -- Not once in the four hundred years since the dawn of the Royal Knights has the Kingdom found itself in such peril. Let us take up our pikes and stand our ground to ensure another four centuries of prosperity!
        IT_IS_OFTEN_IN_TIMES_OF_STRIFE_THAT                                   = 12465,  -- It is often in times of strife that a man's true nature is revealed. Will you stand tall in the face of fear, or run and cower in the wake of your mother's dress?
        WHILE_OUR_HOLY_DOCTRINES_SPECIFICALLY_PROHIBIT_THE_TAKING             = 12466,  -- While our holy doctrines specifically prohibit the taking of another life, you need not hesitate on the battlefield. The Church has branded the beastmen enemies of Altana. The purification must begin! It is the will of the Goddess!!!
        AFTER_YEARS_OF_TRAINING_IN_THE_FAR_EAST                               = 12467,  -- After years of training in the Far East, I return only to find my nation burning at the hands of the infernal beastman hordes. The heathens shall pay dearly... My work has only just begun.
        YOU_HAVE_THE_LOOK_OF_A_FINE_WARRIOR                                   = 12468,  -- You have the look of a fine warrior. It is a pity you are not one of my Crimson Wolves.
        THE_EYES_OF_THE_GODDESS_ARE_EVER_UPON                                 = 12469,  -- The eyes of the Goddess are ever upon us. We must remain steadfast against the evils from without, as well as those from within.
        THE_REPUBLIC_WAS_FORMED_WITH_THE_BLOOD_AND                            = 12470,  -- The Republic was formed with the blood and sweat of the people. The flames of freedom must continue to light our furnaces of strength. The waters of civilization must continue to turn our wheels of ingenuity!
        TURTLE_SLEEPS_IN_A_ROCKY_DENT_CAUSE_HE                                = 12471,  -- Turtle sleeps in a rocky dent 'Cause he's not a citizent Strike him down with sword and stavet Stick a blue flag in his gravet
        WE_MAY_HAVE_THE_UPPER_HAND_IN_TECHNOLOGY                              = 12472,  -- We may have the upper hand in technology and munitions, but the enemy's advantage lies in their sheer numbers. The Allied Campaign will not win in a day, soldier. Make every bullet count.
        THE_METALWORKS_STRATEGIES_ARE_TOO_TIMID_FOR_MY                        = 12473,  -- The Metalworks' strategies are too timid for my taste. The beastmen are nothing but dominoes, waiting to be toppled. A swift, aggressive assault is the only way to victory.
        MOVE_ALONG_SOLDIER_I_HAVE_NOTHING_TO_SAY                              = 12474,  -- Move along, soldier. I have nothing to say to you.
        HALT_IF_YOU_RE_NOT_ONE_OF_THE                                         = 12475,  -- Halt! If you're not one of the Fourth, then get your sorry tail over to the recruitment office on the double! And if you are one of us, then what the hell are you doing here talking to me!? Get back on the battlefield! About...FACE!
        HEAVY_INFANTRY_FIVE_COLUMNS_OF_200_TWO_100                            = 12476,  -- ...Heavy infantry, five columns of 200... Two 100-knight regiments... Enemy force casualties estimated at 5,000... Oh, I apologize, soldier. I've spent the past few nights preparing for a joint operation with San d'Oria's Royal Knights.
        YOU_LOOK_LIKE_YOU_VE_SEEN_BETTER_DAYS                                 = 12477,  -- You look like you've seen better days, soldier. Let me guess, it's the war that's bringing you down. What you need is a little music in your life!
        IF_IT_WEREN_T_FOR_THE_GALKAN_HEAVY                                    = 12478,  -- If it weren't for the Galkan heavy infantry, this nation wouldn't last a month against the turtlebacks. And what thanks do we get? A handful of stale army biscuits!
        HAVE_YOU_EVER_STOPPED_TO_PONDER_WHAT_THAT                             = 12479,  -- Have you ever stopped to ponder what that comet might truly portend? I'd like to believe it is a message of hope--that soon this age of darkness will come to a close...
        OH_WHATEVER_HAS_BECOME_OF_MY_SWEET_WINDURST                           = 12480,  -- Oh, whatever has become of my sweet Windurst? Rabble running through the streets, streets overrun with rabble! Why are you even speaking to me!? Does the title Master Caster no longer garner even an onz of respect!?
        AH_THE_FATES_HAVE_BROUGHT_YOU_TO_GARIRI                               = 12481,  -- Ah, the Fates have brought you to Gariri the Magnificent! Why am I thus called, you ask? Why, because only I was magnificent enough to decryptify those mysteriously marvelous Near Eastern tomes and open a window to...the Other Side!
        WE_ALL_WEAR_MASKS_BECAUSE_DEEP_DOWN_INSIDE                            = 12482,  -- We all wear masks because deep down inside we are nothing but beasts. The question I ask you is, to which do you submit--the mask, or the beast?
        GUTTLER_I_TOLD_YOU_TO_KEEP_QUI_AHAHAHAH                               = 12483,  -- (Guttler! I told you to keep qui--) Ahahahah... Don't mind me, I was just...uh...keeping myself company! (Shhh! If you open your mouth one more ti--) Ahahaha... Uh, were you still there?
        IF_ONLY_THE_PARLIAMENT_OF_PATRIARCHS_WOULD_LOOSEN                     = 12484,  -- If only the Parliament of Patriarchs would loosen the strings on their purses a little more, I would be outside right now roasting up a couple birdmen to snack on!
        HAVE_FUN_WHILE_YOU_CAN_FILTHY_MERCENARY_BECAUSE                       = 12485,  -- Have fun while you can, filthy mercenary, because before long you'll be back on the streets where you belong--replaced by a quiet, obedient army of Cardians!
        NORMALLY_IT_IS_MY_DUTY_TO_PROTECT_THE                                 = 12486,  -- Normally, it is my duty to protect the patriarchs of parliament, but with the fate of Windurst in doubt, I'm forced to lead my loyal pets to the front lines.
        DO_YOU_LIKE_THE_HEADPIECE_I_MADE_IT                                   = 12487,  -- Do you like the headpiece? I made it from my firrrst victim. I wear it to let everrryone know what happens when they cross Mikhe Aryohcha!
        BACK_IN_MY_HOME_ULBUKA_I_HEAR_RUMORS                                  = 12488,  -- Back in my home, Ulbuka, I hear rumors of great riches in eastern lands. But now I am here, and where are riches? I see nothing but Tarus! Ahahahaha!
        YAAAWN_MASTERING_THESE_NEAR_EASTERN_MAGICS_CAN_BE                     = 12489,  -- <Yaaawn>... Mastering these Near Eastern magics can be quite taxing. If I had a choice, I'd rather be back in bed, relaxing...
        I_SAVED_THIS_ONE_ESPECIALLY_FOR_YOU                                   = 12490,  -- I saved this one especially for you!
        HIIIIII_YAH                                                           = 12491,  -- Hiiiiii-yah!
        MY_DEAR_PUPIL_DALZAKK_YOU_STILL_HAVE_MUCH                             = 12492,  -- My dear pupil, Dalzakk. You still have much to learn...
        WITNESS_THE_TRUE_EMBODIMENT_OF_MY_SORROW                              = 12493,  -- Witness the true embodiment of my sorrow.
        HEH_HEH_HEH                                                           = 12494,  -- Heh heh heh!
        GIGGLE                                                                = 12495,  -- <Giggle>...
        WHEHEHEHEH_YOU_THIRSTY_KOPEH                                          = 12496,  -- Wheheheheh! You thirsty, Kopeh?
        COME_KILHWCH_WE_MUST_STRIKE_DOWN_THE_EVIL                             = 12497,  -- Come, Kilhwch! We must strike down the evil which stands before us!
        MY_BROTHERS_AND_SISTERS_RAISE_YOUR_BLADES_FOR                         = 12498,  -- My brothers and sisters! Raise your blades for justice!
        KILHWCH_SILENCE_THOSE_FIENDS                                          = 12499,  -- Kilhwch! Silence those fiends!
        TO_YOUR_FEET_KILHWCH                                                  = 12500,  -- To your feet, Kilhwch!
        LADY_ULLA_WE_MUST_RETREAT                                             = 12501,  -- Lady Ulla. We must retreat.
        HOW_DARE_YOU                                                          = 12502,  -- How dare you!
        THE_RAVEN_SHALT_SPARE_NARY_A_TEAR_FOR                                 = 12503,  -- The raven shalt spare nary a tear for thy demise.
        WATCH_AND_SEE_HOW_A_REAL_MERCENARY_EARRRNS                            = 12504,  -- Watch! And see how a real mercenary earrrns her wage!
        LEAVE_ME_BE_THE_VERGE_OF_BATTLE_IS                                    = 12505,  -- Leave me be. The verge of battle is no time for words.
        FEAR_NOT_MY_FISTS_WILL_GUIDE_US_TO                                    = 12506,  -- Fear not. My fists will guide us to victory.
        MY_DAUGHTER_AWAITS_HER_FATHER_AT_HOME_I                               = 12507,  -- My daughter awaits her father at home. I will permit no Beastman to delay my return.
        BEYOND_THIS_POINT_LIES_THE_SEALED_ROYAL_TOMB                          = 12508,  -- Beyond this point lies the sealed royal tomb of King Ranperre. Tell me, %, do you believe the legends?
        THE_ORC_WAR_MACHINE_DRAWS_NEAR_WE_MUST                                = 12509,  -- The Orc war machine draws near. We must brace ourselves for battle.
        IN_FORMER_TIMES_THIS_ISLAND_WAS_INHABITED_BY                          = 12510,  -- In former times, this island was inhabited by a ferocious tribe of vikings. It is said they braved vast expanses of open sea to arrive here. Romantic, don't you think?
        SURELY_YOU_HAVE_SEEN_THE_TIGERS_THAT_ROAM                             = 12511,  -- Surely you have seen the tigers that roam these downs. They were brought from the northern continent by the Orcs themselves. They are highly prized for their luxurious pelts, though their bloodlust makes them formidable game.
        THE_BROTHERHOOD_OF_THIS_PLACE_ONCE_WELCOMED_ME                        = 12512,  -- The brotherhood of this place once welcomed me long ago. I pray that the years have been kind to them.
        THE_GOLD_MUSKETEERS_OF_THE_REPUBLICAN_ARMY_ARE                        = 12513,  -- The Gold Musketeers of the Republican Army are marshalled by young woman. Such talk is sure to inspire my daughter.
        BASTOK_WAS_FORCED_TO_ABANDON_THE_PALBOROUGH_MINES                     = 12514,  -- Bastok was forced to abandon the Palborough Mines following a Beastman invasion. How an army such as the Republic's could permit such an affront baffles me to no end.
        THE_VILLAGE_ELDER_IN_LA_VAULE_TOLD_ME                                 = 12515,  -- The village elder in La Vaule told me of the so-called wyrm deity of Grauberg. Of course, I am sure it is nothing more than folktales. Still, my curiosity is piqued...
        STRANGE_I_AM_CERTAIN_THE_VEGETATION_OF_THIS                           = 12516,  -- Strange... I am certain the vegetation of this area is different from when I last visited. Surely I would not have allowed myself to forget such beautiful flowers.
        SUCH_DEVASATION_EVEN_THE_RESILIENT_GOOBBUE_WERE_NOT                   = 12517,  -- Such devasation... Even the resilient Goobbue were not able to survive. I wonder if this place shall ever be restored to its former glory...
        HISTORY_TELLS_US_THAT_IT_WAS_IN_THE                                   = 12518,  -- History tells us that it was in the year 381 that San d'Oria's iron-tempered King Lanfeaur R d'Oraguille came these lands to strike a peace with the Quadav. Whatever happened to the bond that was formed...?
        I_HAVE_SEEN_HERE_TWO_TWINS_WHO_BETWEEN                                = 12519,  -- I have seen here two twins who between them share a power for magic the likes of which I have never seen. This is indeed a strange nation.
        UNFORTUNATE_I_HAD_ALWAYS_WISHED_TO_GAZE_UPON                          = 12520,  -- Unfortunate... I had always wished to gaze upon the fabled magic towers of West Sarutabaruta with my own eyes. Yet I fear I may be too late...
        THIS_FORTRESS_IS_LAUDED_AS_THE_IMPREGNABLE_POINT                      = 12521,  -- This fortress is lauded as the impregnable point of Windurst's defenses. Goddess forbid, should it happen to be taken, Windurst is unlikely to last more than a month's time.
        THESE_WINDBLOWN_SANDS_REAK_HAVOC_ON_MY_THROAT                         = 12522,  -- These windblown sands reak havoc on my throat. I look forward to a cup of my daughter's fine Batallia tea.
        TAKE_HEED_I_HAVE_SEEN_BEASTMAN_DUG_BATTLE                             = 12523,  -- Take heed, %. I have seen Beastman-dug battle trenches throughout these plains. Should you be found, your life is forfeit.
        THERE_IS_AN_OMINOUS_FEELING_IN_THE_AIR                                = 12524,  -- There is an ominous feeling in the air... This is no place to linger.
        NEVER_HAVE_I_FELT_A_COLD_AS_PIERCING                                  = 12525,  -- Never have I felt a cold as piercing as this. My teeth chatter and my toes grow numb. We would do well to find a place to warm ourselves.
        I_WONDER_IF_IT_WAS_NOT_SOMEWHERE_NEAR                                 = 12526,  -- I wonder if it was not somewhere near here where minister Francmage was dispatched on the Multinational Expedition some 10 years ago.
        NEVER_DID_I_IMAGINE_THE_DAY_WOULD_COME                                = 12527,  -- Never did I imagine the day would come that I would set foot in this accursed place. Has great is our foe's desperation? Do not lower your guard, %.
        AND_SO_WE_BREACH_THE_ENEMY_S_INNER                                    = 12528,  -- And so we breach the enemy's inner sanctum. Expect anything, %! And don't die on me!
        AS_THE_ALLIED_FORCES_HAVE_LONG_MAINTAINED_THIS                        = 12529,  -- As the Allied Forces have long maintained, this citadel would be ideally suited to the defense of Jeuno.
        A_WELL_CONCEIVED_STRATEGY_A_STRONGHOLD_ESTABLISHED_UNDER              = 12530,  -- A well conceived strategy... A stronghold established under the cover of the nest of these vile crawlers. It is almost surely to be overlooked by the enemy.
        OH_MIGHTY_ALTANA_BE_THE_SWORD_IN_MY                                   = 12531,  -- Oh, mighty Altana, be the sword in my hand. With you, the swift cannot flee, nor the strong escape. Receive mine enemies, for the mercy of the Goddess embraces even the wicked.
        HEH_HEH_HEH_WONDER_WHAT_TECHNIQUE_I_SHOULD                            = 12532,  -- Heh heh heh! Wonder what technique I should try out on these ol' beastmen chumps.
        HAHA_WHO_WILL_BE_THE_NEXT_DARLING_RECIPIENT                           = 12533,  -- Haha... Who will be the next darling recipient of my spells?
        RED_BLOOD_BLUE_BLOOD_ANY_COLORRR_BLOOD_IF                             = 12534,  -- Red blood, blue blood, any colorrr blood. If it bleeds, we can kill it!
        WHAT_S_TAKING_SO_LONG_I_M_GETTING                                     = 12535,  -- What's taking so long? I'm getting all antsy-wantsy! My pets are I are all bad at staying still...
        DO_NOT_FEAR_RIGHTEOUSNESS_WILL_PREVAIL_I_SHALL                        = 12536,  -- Do not fear. Righteousness will prevail. I shall show you victory!
        PROMISE_ME_ONE_THING_SHOULD_ANYTHING_HAPPEN_TO                        = 12537,  -- Promise me one thing. Should anything happen to me... Look after my daughter.
        I_RECKON_I_LL_BE_EARNIN_MY_KEEP                                       = 12538,  -- I reckon I'll be earnin' my keep. Won't be doin' nothin' extra, though. Don't be expectin' me to risk my hide without my due an' proper, mm-hmmm.
        BRAVO_REALLY_IS_A_DEAR_ONCE_YOU_GET                                   = 12539,  -- Bravo really is a dear once you get to know him. It's just that in the heat of battle he... Well, you'll see.
        MY_BLADE_KYOMON_ANTICIPATES_MUCH_BEASTMAN_BLOOD_THIS                  = 12540,  -- My blade, Kyomon, anticipates much beastman blood. This battle may prove interesting, yet.
        LOOK_TO_ME_MORTALS_AND_BE_HAUNTED_FOR                                 = 12541,  -- Look to me, mortals! And be haunted for the rest of your brief time in this world!
        FOR_A_SPLIT_SECOND_YOU_THOUGHT_YOU_SAW                                = 12542,  -- For a split second, you thought you saw Titania turn and shoot you a tiny smile.
        THE_FLOWER_ATOP_BABBAN_NY_MHEILLEA_S_HEAD                             = 12543,  -- The flower atop Babban Ny Mheillea's head appears to be in full bloom!
        RIBBIT_RIBBIT                                                         = 12544,  -- Ribbit! Ribbit!
        YOU_D_BETTER_WATCH_YOUR_BACK                                          = 12545,  -- You'd better watch your back!
        DON_T_TAKE_THIS_PERSONALLY_BUT_I_VE                                   = 12546,  -- Don't take this personally, but I've got children to feed.
        TIME_TO_HAVE_SOME_FUN                                                 = 12547,  -- Time to have some fun!
        RECKON_IT_S_TIME_TUH_EARN_MY_KEEP                                     = 12548,  -- Reckon it's time tuh earn my keep, mm-hmm.
        COME_NOW_BRAVO_IT_S_HIGH_TIME_WE                                      = 12549,  -- Come now, Bravo! It's high time we taught these beasts what a wyvern is truly capable of!
        HEHE_SO_MANY_WILLING_TO_BE_SACRIFICED                                 = 12550,  -- Hehe, so many willing to be sacrificed!
        HMPH_PERHAPS_I_SHOULD_JUST_BURN_THE_EYES                              = 12551,  -- Hmph. Perhaps I should just burn the eyes of these infidels with my true form.
        I_FEAR_NOT_DEATH_FOR_THE_GODDESS_AWAITS                               = 12552,  -- I fear not death, for the Goddess awaits us with open arms.
        IT_IS_NOT_YET_YOUR_TIME                                               = 12553,  -- It is not yet your time.
        BE_STRONG_FOR_THE_GODDESS_IS_WITH_YOU                                 = 12554,  -- Be strong, for the Goddess is with you, always.
        RETURN_TO_THE_DUST_WHENCE_YOU_CAME_RANDGRITH                          = 12555,  -- Return to the dust whence you came! Randgrith!!!
        SAINTS_AND_HEROES_GLORY_AND_DESPAIR_OF_THESE                          = 12556,  -- Saints and heroes...glory and despair... Of these I shall sing unto my dying breath.
        TWHEN_WORK_HAS_ENDED_STAY_NOT_LATE_RETURN                             = 12557,  -- tWhen work has ended stay not late. @Return to where thy dearest awaits.
        TO_GENTLE_GODDESS_OF_THE_DAWN_THOU_BRIGHTEN                           = 12558,  -- tO gentle Goddess of the Dawn, thou brighten the black of night. @Hear our song and heed our call, and bathe us in your delight.
        TPRESS_FORWARD_VALIANT_SOLDIERS_GLORY_DRAWS_NEARER_STILL              = 12559,  -- tPress forward valiant soldiers, glory draws nearer still. @Thy deeds shall resound forever, by my stirring song fulfilled.
        TLOYAL_CHILDREN_OF_ALTANA_ARISE_AND_BE_SUSTAINED                      = 12560,  -- tLoyal children of Altana, arise and be sustained. @Be nourished in thine undying faith, and bask in victory's refrain.
        TSING_DANCE_LAUGH_AND_CRY_LET_SWEAT_RAIN                              = 12561,  -- tSing! Dance! Laugh, and cry! Let sweat rain down in floods! @Ride upon this rhythmic beat, make seethe thy red life blood!
        TDANCE_THINE_ELEGANT_AIRY_STEPS_THAT_HAS_WON                          = 12562,  -- tDance thine elegant, airy steps that has won a thousand hearts. @Enchant, enthrall, and captivate, treat none with disregard.
        HONORED_AM_I_TO_HAVE_THIS_CHANCE_TO                                   = 12563,  -- Honored am I to have this chance to share the same stage with you.
        ARMY_UNIT_DEPLOYED_TO                                                 = 12564,  -- [Sand/Bas/Win/Orc/Quad/Yag/Kindred]Army Unit # deployed to [Sand/Ronfa/ugner/Vunkerl/Batallia/La Vaule/Necro/Bastok/Gusta/Grauberg/Passhow/Rolanberry/Beadeaux/Crawler/Win/Saruta/Fort K/Meriphataud/Sauromugue/Oztroja/G Citadel/Glacier/Xarca/Zvahl Out/Zvahl In/Throne Room]...
        ARMY_UNIT_IS_RESTING_FOR_MINUTE_S                                     = 12565,  -- [San d'Orian/Bastokan/Windurstian/Orcish/Quadav/Yagudo/Kindred]Army Unit # is resting for # minute(s)...
        TALLYING_CAMPAIGN_RESULTS                                             = 12566,  -- Tallying Campaign Results...
