        AND_WE_RE_OFF_TO_HEAVENS_TOWER                                        = 13182,  -- And we're off to Heavens Tower!
        IT_SEEMS_ALL_ARE_PRESENT_SO_I_LL                                      = 13183,  -- It seems all are present, so I'll begin at once.
        IT_HARDLY_NEEDS_BE_SAID_THAT_THE_SITUATION                            = 13184,  -- It hardly needs be said that the situation faced by our Federation army--nay, that of the entire Allied Forces--is dire.
        WITH_THE_DEFENSE_OF_FORT_KARUGO_NARUGO_AND                            = 13185,  -- With the defense of Fort Karugo-Narugo and of Windurst itself, not to mention the recent skirmish at Sauromugue, our resources and manpower are being stretched to their very limits.
        THE_CALL_FOR_BACKUP_ON_THE_JEUNOAN_FRONT                              = 13186,  -- The call for backup on the Jeunoan front has only depleted our forces further.
        NO_LONGER_DO_WE_HAVE_THE_LUXURY_OF                                    = 13187,  -- No longer do we have the luxury of sitting around to ponder our next move. We must act, and act now.
        ID_13188                                                              = 13188,  -- ...
        NOR_IS_WINDURST_ALONE_OUR_ALLIES_TOO_FACE                             = 13189,  -- Nor is Windurst alone. Our allies, too, face the selfsame plight.
        IT_IS_IN_THESE_GRIM_TIMES_THAT_THE                                    = 13190,  -- It is in these grim times that the Allied Forces have decided to cast the die. To embark on the one path that may yet lead us to victory...
