        UNDERSTOOD_SIR                                                        = 13536,  -- Understood, sir!
        MAY_THE_GODDESS_KEEP_YOU                                              = 13537,  -- May the Goddess keep you...
        CAN_T_YOU_SEE_THAT_I_M_OCCUPIED                                       = 13538,  -- Can't you see that I'm occupied with my duties? I'm far too busy defending this realm from the forces of darkness to engage in idle chit-chat with ungrateful civilians like you. Now, begone!
