        NOW_IF_YOU_LL_EXCUSE_US_WE_HAVE                                       = 13572,  -- Now if you'll excuse us, we have an important audience with the big cheese himself--er, even if he doesn't know it yetaru. Someone has to save our glorious nation while you strays stand around swatting insects with your tails!
        DANGER_ANGER_TARGETASREACHEDUTHORIZEDERIMETER                         = 13573,  -- DaNGer!ANgeR! TaRGeTaSREaCHeDUTHoRiZeDErImETeR!
        CEASENDESIST_INITIATINGECOVERYROCEDURE                                = 13574,  -- CeASeNDeSIsT! INiTiaTiNGeCOVeRyrOCeDuRE!
