        TWO_MITHRAN_WAYFARERS_FROM_THE_HOMELAND_TO_BE                         = 13588,  -- Two Mithran wayfarers from the homeland, to be prrrecise. I've just received word that they've arrived safely on Mindartian shores.
        THEY_SHOULD_BE_ARRIVING_AT_THE_RRRENDEZVOUS_POINT                     = 13589,  -- They should be arriving at the rrrendezvous point--the monument that stands on Fort Karugo-Narugo's western embankment--before long. Can I trrrust you to see them safely back here?
        I_D_GO_MYSELF_BUT_AS_YOU_MIGHT                                        = 13590,  -- I'd go myself, but as you might imagine, I have my hands quite full rrreadying the mercenaries and devising a sound strrrategy for the city's defense.
        MOTHERLAND_MITHRA_TEND_TO_BE_DISTRRRUSTFUL_SORTS_AS                   = 13591,  -- Motherland Mithra tend to be distrrrustful sorts, as likely to rend the throat of an interloper as give them the time of day. But don't worry. A mention of my name should be enough to keep their claws sheathed.
        AT_LEAST_I_PRRRAY_AS_MUCH_FOR_YOUR                                    = 13592,  -- ...At least I prrray as much, for your sake. Ha-ha!
        HMM_WHAT_MAKES_YOU_THE_LUCKY_MAN_WOMAN                                = 13593,  -- Hmm? What makes you the lucky man/woman] for the job, you ask?
        WHY_YOU_VE_SEEN_HOW_JEALOUS_MY_GIRLS                                  = 13594,  -- Why, you've seen how jealous my girls get every time I grace a member of the fairer sex with a glance. If they discovered that I'd perrrsonally invited two lovely ladies to my humble abode, why, the ensuing battle would send shivers up the spine of the Shadow Lord himself!
