        TAKE_CARE_TO_BE_NEITHER_WITNESSED_NOR_HEARD                           = 13598,  -- Take care to be neither witnessed nor heard by a soul. Least of all the Shadow Lord's minions...or any of your fellow mercenaries of the female perrrsuasion.
        IN_FACT_I_VE_GOT_JUST_THE_WAY                                         = 13599,  -- In fact, I've got just the way for the three of you to keep an especially low prrrofile on your return.
        YOU_RRRECALL_THE_SUBTERRANEAN_PASSAGE_CONNECTING_FORT_KARUGO          = 13600,  -- You rrrecall the subterranean passage connecting Fort Karugo-Narugo with the capital, do you not? The caverns where you helped us stave off the Yagudo onslaught...
