        AS_DO_I_SYU_BUT_WE_VE_NO                                              = 13605,  -- As do I, Syu. But we've no time to stop and smell the rrroses. Lead us to Lehko, friend.
        IT_S_MY_PLEASURE_TO_WELCOME_YOU_TO                                    = 13606,  -- It's my pleasure to welcome you to Windurst, Nhev Befrathi. Or should I say, Chieftainness...?
        CALL_ME_WHAT_YOU_WILL_A_WOMAN_IN                                      = 13607,  -- Call me what you will. A woman in my position has little use for forrrmalities. This is my daughter, Syu.
        YOU_VE_DONE_WELL_TO_LEAD_MY_FRRRIENDS                                 = 13608,  -- You've done well to lead my frrriends safely here, %. Once again, you prove yourself worthy of all the trrrust I place in you, and then some.
        AND_WITH_THAT_NHEV_LET_US_PRRROCEED_WITH                              = 13609,  -- And with that, Nhev, let us prrroceed with our trrransaction. The item we spoke of--
        IS_HERE                                                               = 13610,  -- ...Is here.
        THE_BOW_OF_LIGHT                                                      = 13611,  -- The Bow of Light...
        NEVER_DID_I_IMAGINE_I_WOULD_GAZE_UPON                                 = 13612,  -- ...Never did I imagine I would gaze upon it again with these two eyes.
        LEHKO                                                                 = 13613,  -- Lehko...?
        THERE_IS_NO_NEED_FOR_CONCERRRN_NHEV_IS                                = 13614,  -- There is no need for concerrrn, Nhev. % is a friend--a staunch ally who has demonstrated his/her] loyalty time and again.
        PERRRHAPS_YOU_HAVE_HEARD_THE_TALES                                    = 13615,  -- Perrrhaps you have heard the tales, %.
        IT_WAS_SOME_TEN_YEARS_AGO_A_MITHRAN                                   = 13616,  -- It was some ten years ago. A Mithran wayfarer returned to the motherland after a brief sojourn on these shores. She took with her a souvenir acquirrred in her travels: a most currrious stone...
