        THE_TRRRAVELER_S_NAME_WAS_YOW_RABNTAH_AND                             = 13618,  -- The trrraveler's name was Yow Rabntah, and with that stone, she fashioned a bow. An ensorcelled weapon of the most exquisite crrraftsmanship--so beautiful, and so deadly...
        THE_BOW_OF_LIGHT_2                                                    = 13619,  -- ...The Bow of Light.
        IT_IS_WELL_POSSIBLE_THAT_YOW_RABNTAH_HAD                              = 13620,  -- It is well possible that Yow Rabntah had only the purrrest of intentions--that the bow was meant to prrrotect her beloved homeland, and nothing more.
